300				if useOrg == "" {
301					return fmt.Errorf("org not found. Configure a default org or pass the --org flag")
302				}
303	
304				token, err := configManager.GetToken(useOrg)
305				if err != nil {
306					return fmt.Errorf("failed logging out (%w)", err)
307				}
308				if err = configManager.DeleteToken(useOrg); err != nil {
309					return fmt.Errorf("failed deleting the token from cache (%w)", err)
310				}
311	
312				lipgloss.Printf(
313					"%s Successfully logged out %s from %s\n",
314					styles.CheckMark,
315					styles.Bold.Render(token.Claims.Email),
316					styles.Bold.Render(token.Claims.OrgName),
317				)
318	
319				return nil
320			},
321		}
322		cmd.Flags().StringVar(&org, "org", "", "Organization name (uses default if not specified)")
323		return cmd
