326	func printTokenRefreshStatus(token *auth.Token, expired bool) []string {
327		if token.RefreshToken != "" && token.AuthBaseURL != "" {
328			if expired {
329				return []string{
330					"Silent refresh: available (will refresh on next API call)",
331					fmt.Sprintf("Auth base URL: %s", styles.Bold.Render(token.AuthBaseURL)),
332				}
333			}
334	
335			return []string{
336				"Silent refresh: available",
337				fmt.Sprintf("Auth base URL: %s", styles.Bold.Render(token.AuthBaseURL)),
338			}
339		}
340	
341		lines := []string{"Silent refresh: unavailable"}
342		if expired {
343			lines = append(lines, "Action: run 'port auth login' to renew the token")
344		}
345		return lines
346	}
347	
348	func loginWithStdinToken(configManager *config.ConfigManager, org string) error {
349		token, err := auth.ReadTokenFromStdin()
350		if err != nil {
351			return fmt.Errorf("failed reading token (%w)", err)
352		}
353	
354		parsed, err := auth.ParseToken(token)
355		if err != nil {
356			return fmt.Errorf("failed parsing token (%w)", err)
357		}
358	
359		err = configManager.StoreToken(org, parsed)
360		if err != nil {
361			return fmt.Errorf("failed storing token (%w)", err)
362		}
363	
364		lipgloss.Printf("%s Using provided token\n", styles.CheckMark)
365	
366		return err
367	}
