312		}
313		parsed.AuthBaseURL = authBaseURL
314		if tokenResp.RefreshToken != "" {
315			parsed.RefreshToken = tokenResp.RefreshToken
316		} else {
317			// Some providers only rotate refresh tokens occasionally, so keep the
318			// existing one when the response omits a replacement token.
319			parsed.RefreshToken = oldRefreshToken
320		}
321	
322		return parsed, nil
323	}
