96	// LoadWithDualOverrides loads configuration with dual org support.
97	// Returns config, base org config, and target org config.
98	// Precedence: CLI flags > env vars > config file > defaults.
99	func (cm *ConfigManager) LoadWithDualOverrides(
100		baseClientID, baseClientSecret, baseAPIURL, baseOrg string,
101		targetClientID, targetClientSecret, targetAPIURL, targetOrg string,
102	) (*Config, *OrganizationConfig, *OrganizationConfig, error) {
103		// Load base config (file + env vars)
104		cfg, err := cm.Load()
105		if err != nil {
106			return nil, nil, nil, err
107		}
108	
109		// Resolve base org config
110		baseOrgConfig, err := cm.resolveOrgConfig(cfg, baseClientID, baseClientSecret, baseAPIURL, baseOrg, "base")
111		if err != nil {
112			return nil, nil, nil, fmt.Errorf("failed to resolve base org: %w", err)
113		}
114	
115		// Resolve target org config
116		targetOrgConfig, err := cm.resolveOrgConfig(cfg, targetClientID, targetClientSecret, targetAPIURL, targetOrg, "target")
117		if err != nil {
118			return nil, nil, nil, fmt.Errorf("failed to resolve target org: %w", err)
119		}
120	
121		// If either config is nil and we have an org name, try to get from config file
122		if baseOrgConfig == nil && baseOrg != "" {
123			baseOrgConfig, err = cfg.GetOrgConfig(baseOrg)
124			if err != nil {
125				return nil, nil, nil, fmt.Errorf("failed to get base org config: %w", err)
126			}
127		}
128	
129		if targetOrgConfig == nil && targetOrg != "" {
130			targetOrgConfig, err = cfg.GetOrgConfig(targetOrg)
131			if err != nil {
132				return nil, nil, nil, fmt.Errorf("failed to get target org config: %w", err)
133			}
134		}
135		if baseOrgConfig == nil {
136			c := cfg.Organizations[cfg.DefaultOrg]
137			baseOrgConfig = &c
138		}
139	
140		return cfg, baseOrgConfig, targetOrgConfig, nil
141	}
