143	// resolveOrgConfig resolves organization config with CLI/env overrides.
144	func (cm *ConfigManager) resolveOrgConfig(cfg *Config, clientID, clientSecret, apiURL, orgName, orgType string) (*OrganizationConfig, error) {
145		// Check environment variables if CLI flags not provided
