164				apiURL = os.Getenv("PORT_API_URL")
165			}
166		}
167	
168		// If no CLI/env overrides and no org name specified, return nil to allow fallback
169		if clientID == "" && clientSecret == "" && apiURL == "" && orgName == "" {
170			return nil, nil
171		}
172	
173		// Apply CLI/env overrides if provided
174		if clientID != "" || clientSecret != "" || apiURL != "" {
175			overrideOrg := orgName
176			if overrideOrg == "" {
177				overrideOrg = cfg.DefaultOrg
178			}
179			if overrideOrg == "" {
