208	   export PORT_CLIENT_SECRET="your-client-secret"
209	   export PORT_TARGET_CLIENT_ID="your-target-client-id"
210	   export PORT_TARGET_CLIENT_SECRET="your-target-client-secret"
211	
212	3. Configuration file:
213	   Run: port config --init
214	   Then edit: %s`, orgType, cm.configPath)
215				}
216			}
217			if overrideConfig.ClientSecret == "" {
218				if exists {
219					overrideConfig.ClientSecret = existingOrg.ClientSecret
220				} else {
221					return nil, fmt.Errorf(`missing credentials for %s org
222	
223	To authenticate, provide credentials using one of these methods:
224	
225	1. CLI flags (recommended for standalone binaries):
226	   port export --client-id YOUR_CLIENT_ID --client-secret YOUR_CLIENT_SECRET
227	   port import --target-client-id YOUR_CLIENT_ID --target-client-secret YOUR_CLIENT_SECRET
228	
229	2. Environment variables:
230	   export PORT_CLIENT_ID="your-client-id"
231	   export PORT_CLIENT_SECRET="your-client-secret"
