308	// loadFromFile loads configuration from YAML file.
309	func (cm *ConfigManager) loadFromFile(cfg *Config) error {
310		data, err := os.ReadFile(cm.configPath)
311		if err != nil {
312			return err
313		}
314	
315		fileConfig := &configFileYAML{}
316		if err := yaml.Unmarshal(data, fileConfig); err != nil {
317			return err
318		}
319	
320		// Merge file config into defaults
321		if fileConfig.DefaultOrg != "" {
322			cfg.DefaultOrg = fileConfig.DefaultOrg
323		}
324		if fileConfig.Organizations != nil {
325			cfg.Organizations = fileConfig.Organizations
326		}
327		if fileConfig.Backend.URL != "" {
328			cfg.Backend.URL = fileConfig.Backend.URL
329		}
330		if fileConfig.Backend.Timeout != 0 {
331			cfg.Backend.Timeout = fileConfig.Backend.Timeout
332		}
333		cfg.Skills = mergeSkillsYAML(fileConfig.Skills, fileConfig.LegacyPlugin)
334	
335		return nil
336	}
337	
338	// configFileYAML mirrors Config on disk, including the legacy `plugin` key for backward compatibility.
339	type configFileYAML struct {
340		DefaultOrg    string                        `yaml:"default_org"`
341		Organizations map[string]OrganizationConfig `yaml:"organizations"`
342		Backend       BackendConfig                 `yaml:"backend"`
343		Skills        SkillsConfig                  `yaml:"skills,omitempty"`
344		LegacyPlugin  SkillsConfig                  `yaml:"plugin,omitempty"`
345	}
346	
347	// mergeSkillsYAML prefers the `skills` section; if it has no selection, falls back to legacy `plugin`.
348	func mergeSkillsYAML(skills, legacyPlugin SkillsConfig) SkillsConfig {
349		if skills.HasSelection() {
350			return skills
351		}
352		return legacyPlugin
353	}
354	
355	func (cm *ConfigManager) AsMap(cfg *Config) (map[string]any, error) {
356		data, err := os.ReadFile(cm.configPath)
357		if err != nil {
358			return nil, err
359		}
360	
361		fileConfig := map[string]any{}
362		if err := yaml.Unmarshal(data, &fileConfig); err != nil {
363			return nil, err
364		}
365	
366		return fileConfig, nil
367	}
368	
369	// loadFromEnv loads configuration from environment variables.
370	func (cm *ConfigManager) loadFromEnv(cfg *Config) {
371		// Backend URL
372		if backendURL := os.Getenv("PORT_CLI_BACKEND_URL"); backendURL != "" {
373			cfg.Backend.URL = backendURL
374		}
375	
376		// Default org from environment
377		if defaultOrg := os.Getenv("PORT_DEFAULT_ORG"); defaultOrg != "" {
378			cfg.DefaultOrg = defaultOrg
379		}
380	
381		// Single organization from environment variables
382		clientID := os.Getenv("PORT_CLIENT_ID")
383		clientSecret := os.Getenv("PORT_CLIENT_SECRET")
384		apiURL := os.Getenv("PORT_API_URL")
385		if apiURL == "" {
386			apiURL = "https://api.getport.io/v1"
387		}
388	
389		if clientID != "" && clientSecret != "" {
390			// Create or override the "default" organization
391			orgName := cfg.DefaultOrg
392			if orgName == "" {
393				orgName = "default"
394			}
395	
396			if cfg.Organizations == nil {
397				cfg.Organizations = make(map[string]OrganizationConfig)
398			}
399	
400			cfg.Organizations[orgName] = OrganizationConfig{
401				ClientID:     clientID,
402				ClientSecret: clientSecret,
403				APIURL:       apiURL,
404			}
405	
406			// Set as default org if not set
407			if cfg.DefaultOrg == "" {
408				cfg.DefaultOrg = orgName
409			}
410		}
411	}
412	
413	// CreateDefaultConfig creates a default configuration file.
414	func (cm *ConfigManager) CreateDefaultConfig() error {
415		// Create default config
416		defaultConfig := &Config{
417			DefaultOrg: "production",
418			Organizations: map[string]OrganizationConfig{
419				"production": {
420					ClientID:     "your-client-id",
421					ClientSecret: "your-client-secret",
422					APIURL:       "https://api.getport.io/v1",
423				},
424				"staging": {
425					ClientID:     "your-staging-client-id",
426					ClientSecret: "your-staging-client-secret",
427					APIURL:       "https://api.getport.io/v1",
428				},
429			},
430			Backend: BackendConfig{
431				URL:     "http://localhost:8080",
432				Timeout: 300,
433			},
434		}
435	
436		return cm.Write(defaultConfig)
437	}
438	
439	func (cm *ConfigManager) Write(cfg *Config) error {
440		// Ensure directory exists
441		dir := filepath.Dir(cm.configPath)
442		if err := os.MkdirAll(dir, 0o755); err != nil {
443			return fmt.Errorf("failed to create config directory: %w", err)
444		}
445	
446		// Write to file
447		data, err := yaml.Marshal(cfg)
448		if err != nil {
449			return fmt.Errorf("failed to marshal config: %w", err)
450		}
451	
452		if err := os.WriteFile(cm.configPath, data, 0o644); err != nil {
453			return fmt.Errorf("failed to write config file: %w", err)
454		}
455	
456		return nil
457	}
458	
459	func (cm *ConfigManager) WriteBytes(data []byte) error {
460		dir := filepath.Dir(cm.configPath)
461		if err := os.MkdirAll(dir, 0o755); err != nil {
462			return fmt.Errorf("failed to create config directory: %w", err)
463		}
464	
465		if err := os.WriteFile(cm.configPath, data, 0o644); err != nil {
466			return fmt.Errorf("failed to write config file: %w", err)
467		}
468	
469		return nil
470	}
471	
472	// WriteOrgIfMissing adds the org to the config if its missing.
473	func (cm *ConfigManager) WriteOrgIfMissing(org string, apiUrl string) (*Config, error) {
474		cfg, err := cm.Load()
475		if err != nil {
476			return nil, err
477		}
478	
479		newDefault := strings.ToLower(org)
480		newDefault = strings.ReplaceAll(newDefault, " ", "_")
481	
482		if existingOrg, ok := cfg.Organizations[newDefault]; !ok {
483			cfg.Organizations[newDefault] = OrganizationConfig{APIURL: apiUrl}
484		} else {
485			existingOrg.APIURL = apiUrl
486			cfg.Organizations[newDefault] = existingOrg
487		}
488	
489		err = cm.Write(cfg)
490		if err != nil {
491			return nil, fmt.Errorf("failed saving default org as %s (%w)", org, err)
492		}
493		return cfg, nil
494	}
495	
496	// LoadSkillsConfig loads the skills section from the config file.
497	func (cm *ConfigManager) LoadSkillsConfig() (*SkillsConfig, error) {
498		cfg, err := cm.Load()
499		if err != nil {
500			return nil, fmt.Errorf("failed to load config: %w", err)
501		}
502		return &cfg.Skills, nil
503	}
504	
505	// SaveSkillsConfig persists the skills section into the config file, preserving all other fields.
506	func (cm *ConfigManager) SaveSkillsConfig(skills *SkillsConfig) error {
507		cfg, err := cm.Load()
508		if err != nil {
509			// Config file doesn't exist yet -- start from an empty config.
510			// Load() wraps os errors, so check the file directly.
511			if _, statErr := os.Stat(cm.configPath); errors.Is(statErr, os.ErrNotExist) {
512				cfg = &Config{Organizations: make(map[string]OrganizationConfig)}
513			} else {
514				// File exists but couldn't be loaded (parse error, permissions, etc.)
515				return fmt.Errorf("failed to load existing config: %w", err)
516			}
517		}
518	
519		cfg.Skills = *skills
520	
521		dir := filepath.Dir(cm.configPath)
522		if err := os.MkdirAll(dir, 0o755); err != nil {
523			return fmt.Errorf("failed to create config directory: %w", err)
524		}
525	
