226	// WriteSkills writes SKILL.md files (plus references, assets, scripts, and
227	// additional files) for each skill,
228	// routing each one based on its Location property:
229	//   - SkillLocationGlobal  → written into every dir in globalTargets
230	//   - SkillLocationProject → written into the matching tool sub-directory
231	//     inside every projectDir (e.g. <projectDir>/.agents/skills/port/…)
232	func WriteSkills(skills []Skill, groups []SkillGroup, globalTargets []string, projectDirs []string) error {
233		globalSkills := make([]Skill, 0, len(skills))
234		projectSkills := make([]Skill, 0)
235		for _, s := range skills {
236			if s.Location == SkillLocationProject {
237				projectSkills = append(projectSkills, s)
238			} else {
239				globalSkills = append(globalSkills, s)
240			}
241		}
242	
243		if err := writeSkillsToTargets(globalSkills, globalTargets); err != nil {
244			return err
245		}
246	
247		if len(projectDirs) > 0 && len(projectSkills) > 0 {
248			projectTargets := buildProjectTargets(globalTargets, projectDirs)
249			if err := writeSkillsToTargets(projectSkills, projectTargets); err != nil {
250				return err
251			}
252		}
253	
254		return nil
255	}
