257	// buildProjectTargets creates project-level target paths by combining each
258	// project directory with the tool sub-directory derived from the global
259	// targets. When a tool defines a ProjectDir override, that name is used under
260	// each project dir instead of Dir (rare; most tools use Dir only).
261	func buildProjectTargets(globalTargets []string, projectDirs []string) []string {
262		toolDirs := extractProjectDirs(globalTargets)
263		seen := make(map[string]bool)
264		var result []string
265		for _, pd := range projectDirs {
266			for _, td := range toolDirs {
267				p := filepath.Join(pd, td)
268				if !seen[p] {
269					result = append(result, p)
270					seen[p] = true
271				}
272			}
273		}
274		return result
275	}
276	
277	// extractProjectDirs returns the relative directory names to use for
278	// project-scoped skills. For each global target it checks known hook targets:
279	// if the target has a ProjectDir override that directory is used, otherwise
280	// the target's Dir is used. Unrecognized paths fall back to the base name.
281	// Legacy GitHub Copilot paths ending in /.copilot map to ".github".
282	func extractProjectDirs(globalTargets []string) []string {
283		knownTargets := DefaultHookTargets()
284		seen := make(map[string]bool)
285		var dirs []string
286		for _, gt := range globalTargets {
287			expanded := expandHome(gt)
288			matched := false
289			for _, kt := range knownTargets {
290				if matchesTarget(expanded, kt) {
291					d := kt.Dir
292					if kt.ProjectDir != "" {
293						d = kt.ProjectDir
294					}
295					if !seen[d] {
296						dirs = append(dirs, d)
297						seen[d] = true
